{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-heater-multi-action-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕已选中的进料流股 feed-1 的缺失流量规格，以及已选中的加热器 heater-1 在出口温度控制模式下缺少目标温度这两类问题生成候选提案。",
  "issues": [
    {
      "title": "feed-1 缺少流量规格",
      "detail": "诊断直接指出 Cold Feed 缺少流量规格，当前仅见温度与压力规格。",
      "citations": [
        "diag-1",
        "flowdoc-stream-1"
      ]
    },
    {
      "title": "heater-1 缺少出口温度目标",
      "detail": "诊断直接指出 Feed Heater 已配置为 outlet_temperature 控制，但缺少目标出口温度参数。",
      "citations": [
        "diag-2",
        "flowdoc-unit-1"
      ]
    }
  ],
  "answers": [
    {
      "summary": "为当前选中的流股和加热器提出两个最小候选补丁：一个补全进料流量占位，另一个补全加热器出口温度目标占位。",
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 feed-1 增加流量规格占位",
          "target": {
            "type": "stream",
            "id": "feed-1"
          },
          "rationale": "诊断明确指出该流股缺少流量规格；在不假设具体数值的前提下，增加可审查的规格占位是最小修补方式。",
          "patch": {
            "spec_placeholders": [
              {
                "name": "flow_rate",
                "value_type": "number",
                "unit_hint": "kg/h",
                "required": true
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-1"
          ],
          "confidence": 0.98
        },
        {
          "action": "candidate_edit",
          "title": "为 heater-1 增加出口温度目标占位",
          "target": {
            "type": "unit",
            "id": "heater-1"
          },
          "rationale": "该设备已处于 outlet_temperature 控制模式，诊断明确指出缺少目标出口温度；补充参数占位可与现有控制模式直接对应，且不预设工艺目标数值。",
          "patch": {
            "parameter_placeholders": [
              {
                "name": "outlet_temperature_c",
                "value_type": "number",
                "unit_hint": "C",
                "required": true
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1"
          ],
          "confidence": 0.97
        }
      ]
    }
  ]
}
